#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const OUT = path.join(ROOT, 'content', 'bundle.js');

const SOURCES = [
  'lib/logger.js',
  'lib/yaml.js',
  'lib/field-helpers.js',
  'lib/form-filler.js',
  'content/content.js',
];

const parts = SOURCES.map((file) => {
  const fullPath = path.join(ROOT, file);
  const code = fs.readFileSync(fullPath, 'utf8');
  return `/* ===== ${file} ===== */\n${code}`;
});

const banner = `/* Auto-generated by scripts/build-bundle.js — do not edit */\n`;
fs.writeFileSync(OUT, banner + parts.join('\n\n'));
console.log(`Built ${path.relative(ROOT, OUT)} (${SOURCES.length} files)`);
